imagePrompts.prompt:
{
"image_generation_prompt": {
"subject": {
"appearance": "Young Caucasian woman with long blonde hair, wearing a red bandana headband and bright red lipstick.",
"body_details": "Skin has a wet, glossy look with prominent streaks and patches of white car wash soap suds on her torso, abdomen, and legs."
},
"clothing": {
"top": "White t-shirt rolled and cropped high, revealing a leopard-print bikini top underneath.",
"bottom": "Distressed black denim cut-off shorts with a dangling silver pocket chain.",
"footwear": "Extreme high-heel white platform sandals with white straps tied intricately around the ankles."
},
"action_and_pose": {
"posture": "Standing beside the front driver-side fender with her body leaning forward slightly over the hood of the car, creating a pronounced arch in her back. Her hips are angled outward while her shoulders twist subtly toward the camera for a flirtatious retro pin-up stance.",
"hands": "Right hand spread across the wet hood for balance while the left hand slowly squeezes the yellow sponge against the soap-covered windshield.",
"head_and_expression": "Head tilted slightly to the side with a confident teasing smile, maintaining direct eye contact with the camera.",
"legs": "One leg extended straight while the other bends at the knee with the heel lifted slightly, emphasizing the pose and posture."
},
"vehicle": {
"description": "Classic bright red sports car, closely resembling a Porsche 911.",
"features": "Silver 5-spoke alloy wheels with a crest center cap, sleek curved body style, pop-up style headlight housing.",
"condition": "Covered in white soap suds."
},
"props": {
"bucket": "White plastic bucket sitting on the ground near the front tire with the word 'NOAH' clearly printed in bold red lettering.",
"sponge": "Large, thick yellow car washing sponge."
},
"environment": {
"setting": "Dimly lit, vintage-style garage or workshop.",
"background": "Dark wood-paneled walls heavily decorated with assorted vintage license plates (including New York), old metal automotive signs (Chevrolet, Grand Prix), and framed posters.",
"ceiling": "Exposed wooden joists with industrial hanging lights and wiring.",
"floor": "Dark, wet concrete floor covered in puddles of water and thick white soap suds."
},
"lighting_and_atmosphere": {
"lighting": "Dramatic cinematic lighting, high contrast with a flash-photography style spotlight illuminating the woman and the front of the car, leaving the background in deeper shadow.",
"vibe": "Retro pin-up model aesthetic, edgy, automotive garage photoshoot."
},
"camera_and_quality_settings": {
"aspect_ratio": "9:16 vertical portrait",
"resolution": "4k HD, 8k resolution, ultra-detailed.",
"style": "Photorealistic, hyper-realistic, professional editorial photography.",
"lens_and_focus": "Sharp focus on the main subject and car, high depth of field to capture background textures.",
"texture_details": "Lifelike rendering of wet skin, high-gloss reflection on the red car paint, realistic porous texture on the yellow sponge, volumetric rendering of fluffy white soap suds."
}
}
}

